export const THEORY_BANK: TheoryQuestion[] = [
  // ═══ BUDGETING (David Wilson 2003–2023) ═══
  {topic:"Budgeting",year:2003,marks:12,tags:["Principal Budget Factor","Flexible Budget"],q:"Explain Principal Budget Factor. Why prepare a flexible budget and what does it show?",a:"Principal Budget Factor — often called the limiting or key budget factor. It is the factor that limits output and prevents continuous expansion. Usually the principal budget factor is sales demand, but it could be some other limiting factor such as availability of materials.\n\nWhy prepare a flexible budget / what does it show?\n• To compare budgeted costs and actual costs at the same level of activity.\n• To compare like with like.\n• To help in controlling costs or to plan production levels.\n• It shows whether actual costs exceeded or were less than budgeted costs (variances)."},
  {topic:"Budgeting",year:2005,marks:8,tags:["Factors Affecting Sales"],q:"Note on the factors taken into account by Spencer Ltd in arriving at the expected sales in 2006 of 11,700 units.",a:"• Market research\n• Trends\n• Last year sales\n• Opinion of Sales manager and sales representatives\n• Price to be charged\n• State of the economy\n• Competition\n• Luxury versus necessities"},
  {topic:"Budgeting",year:2006,marks:12,tags:["Adverse Variance","Controllable Costs","Uncontrollable Costs"],q:"What is an adverse variance? State why adverse variances may arise in Direct material costs. Explain, with examples, 'controllable' and 'uncontrollable' costs.",a:"Adverse variance: where actual costs exceed budgeted costs. In direct material costs it may arise if the purchase price of materials is higher than expected or if the quantities of material used are higher than expected.\n\nControllable Costs: costs that can be controlled by the manager of a cost centre. She/he makes the decision about the amount of the cost or if it should be incurred and can be held responsible for variances. E.g. all variable costs are controllable.\n\nUncontrollable Costs: costs over which the manager of a cost centre has no control and therefore cannot be held responsible for variances. E.g. rates to the local authority are uncontrollable."},
  {topic:"Budgeting",year:2007,marks:8,tags:["Cash Budget Definition"],q:"Define 'cash budget' and describe two of its advantages.",a:"A cash budget is a forecast or plan of cash inflow and cash outflow over a period.\n\nAdvantages:\n• Highlights whether enough cash will be available to meet future needs.\n• Helps to give advance knowledge so that an overdraft can be arranged if a shortfall occurs.\n• Helps to predict future surpluses so that short-term investment can be made."},
  {topic:"Budgeting",year:2008,marks:10,tags:["Capital Budget","Principal Budget Factor"],q:"Explain what is meant by a Capital Budget. The Principal Budget factor is sales demand in most organisations. State two other items that could also be considered to be the Principal Budget factor.",a:"Capital Budget: deals with any planned capital expenditure (e.g. purchase of fixed assets) and planned capital receipts (e.g. sale of fixed assets). Decisions relating to these items are the responsibility of the Board of Directors. The carrying out of the capital budget is the responsibility of the Financial Controller.\n\nOther Principal Budget Factors (apart from sales demand):\n• Supply of materials\n• Availability of labour\n• Capacity of the plant\n• Availability of capital"},
  {topic:"Budgeting",year:2009,marks:8,tags:["Factors Affecting Sales"],q:"Prepare a note on the factors taken into account by Greene Ltd in arriving at the expected sales of 59,000 units for the six months of 2010.",a:"• Last year sales\n• Market research / opinion of Sales manager and sales representatives\n• Trends / State of the economy\n• Price to be charged\n• Competition\n• Luxuries versus necessities"},
  {topic:"Budgeting",year:2010,marks:6,tags:["Adverse Variance"],q:"What is an adverse variance? State why adverse variances may arise in direct material costs.",a:"An adverse variance is when actual costs exceed budgeted costs. Adverse variances may arise in direct material costs because of an increase in the price of materials or an increase in quantities used."},
  {topic:"Budgeting",year:2011,marks:8,tags:["Master Budget"],q:"Explain the term 'Master Budget'. List the components of a Master Budget for a manufacturing firm.",a:"A Master Budget is a summary of all the other budgets and provides an overview of the operations for the planned period.\n\nComponents for a manufacturing firm:\n• Budgeted manufacturing account\n• Budgeted trading account and profit and loss account\n• Budgeted balance sheet"},
  {topic:"Budgeting",year:2012,marks:10,tags:["Controllable Costs","Uncontrollable Costs","Factors Affecting Sales"],q:"Explain, with examples, 'controllable' and 'uncontrollable' costs. What factors should be taken into account by Din Ltd in arriving at the expected sales of €3,600,000 for the six months of 2012?",a:"Controllable Costs: costs that can be controlled by the manager of a cost centre. She/he makes the decision about the cost and can be held responsible for variances. E.g. all variable costs are controllable. Commission to sales personnel can be controlled by the sales manager.\n\nUncontrollable Costs: costs over which the manager of a cost centre has no control. E.g. rates to the local authority.\n\nFactors for sales estimate:\n• Last year sales from other stores\n• Market research / opinion of sales manager and sales reps\n• Trends / State of the economy\n• Price to be charged\n• Competition\n• Luxuries versus necessities"},
  {topic:"Budgeting",year:2013,marks:8,tags:["Cash Budget Advice","Capital Budget"],q:"What useful information is available to Murray Ltd from the completed cash budget? Explain what is meant by a Capital budget.",a:"From the cash budget Murray Ltd will be able to see:\n• Which months will have a deficit of cash — enabling arrangement of a loan or overdraft.\n• Which months will have a surplus of cash — enabling arrangement of short-term investments.\n• Overdraft facilities required each month up to a maximum.\n• The closing cash position.\n\nCapital Budget: deals with planned capital expenditure (e.g. purchase of a fixed asset) and planned capital receipts (e.g. sale of a fixed asset). Decisions regarding capital items are the responsibility of the Board of Directors. Carrying out of the capital budget is the responsibility of the Financial Controller."},
  {topic:"Budgeting",year:2014,marks:10,tags:["Cash Budget Definition","Principal Budget Factor"],q:"Define what is meant by a Cash Budget and explain two advantages of a Cash Budget. The Principal Budget factor is sales demand in most organisations. State two other factors that could also be considered to be the Principal Budget factor.",a:"A Cash Budget is a plan or forecast that summarises the expected inflows and outflows of cash during a period. It is prepared by the management accountant or the financial accountant.\n\nAdvantages:\n• Anticipates periods when the organisation will have cash surpluses — enabling short-term investments.\n• Anticipates periods when the organisation will have cash deficits — enabling arrangement of a loan or overdraft.\n• Helps ensure there are always enough funds available to meet day-to-day needs of the business.\n\nOther Principal Budget Factors: availability of materials; availability of labour; capacity of the plant; availability of capital."},
  {topic:"Budgeting",year:2015,marks:12,tags:["Controllable Costs","Uncontrollable Costs","Cash Budget Advice"],q:"Explain, with examples, 'controllable' and 'uncontrollable' costs. What options does a business have when it has (a) a cash surplus and (b) a cash deficit? On the basis of the cash budget you have prepared what advice would you give the management of Retro Ltd?",a:"Controllable Costs: costs that can be controlled by the manager of a cost centre — e.g. variable costs; commission to sales staff.\n\nUncontrollable Costs: costs over which the manager has no control — e.g. rates to the local authority.\n\nCash Surplus: money can be placed in short-term investment opportunities to gain maximum interest; surplus could be used to pay off loans or purchase fixed assets.\n\nCash Deficit: arrange alternative sources of finance e.g. bank overdraft; longer periods of credit from suppliers.\n\nAdvice for Retro Ltd:\n• Serious cash shortages in both July and August.\n• Change credit terms for debtors to encourage more prompt payment, e.g. 6% discount for cash in month of sale.\n• Hire equipment instead of buying to reduce cash expenditure, or delay the start date for repayment of the loan.\n• Agree better credit terms with creditors.\n• Examine variable overheads to see if they can be reduced.\n• Examine the wage bill to see if it can be reduced."},
  {topic:"Budgeting",year:2016,marks:10,tags:["Recommendations","Factors Affecting Sales"],q:"What recommendations would you make to Irwin Ltd based on the budgets you have prepared? Outline the factors which Irwin Ltd should take into account when estimating future sales figures.",a:"Recommendations:\n1. Reduce the requirement for closing stock of finished goods, particularly in earlier months, to reduce costs of production.\n2. Negotiate a lower price than €4 per kg from suppliers when buying raw materials — reduces cash expenditure.\n3. Encourage debtors to pay earlier by offering discounts for early payment / reduce the period of credit allowed from 2 months to 1 month — increases receipts.\n4. Postpone the purchase of equipment in July and instead lease the equipment — reduces the deficit in July by €12,000 (€60,000 − €48,000) plus interest and loan repayments of €1,400 thereafter.\n\nFactors for sales estimate:\n1. Market research and trends / opinion of sales representatives.\n2. The price to be charged for the product or service.\n3. The level of competition in the market place.\n4. Whether the economy is expected to grow over the coming months."},
  {topic:"Budgeting",year:2017,marks:8,tags:["Budgetary Control"],q:"Why is it important that a business prepares regular budgets?",a:"• Budgeting is part of the planning process — a financial road map for the business.\n• Budgeting helps define areas of responsibility for staff and motivates staff to achieve targets, improves communication and builds teamwork.\n• Resources of the organisation are used as efficiently as possible and it can adapt quickly to changing circumstances.\n• Budgeted figures can be compared with actual performance; adverse variances can be investigated and action taken to ensure they do not recur."},
  {topic:"Budgeting",year:2018,marks:8,tags:["Contribution","Profit","Flexible Budget"],q:"Distinguish between the terms 'contribution' and 'profit'. Outline why Conlon Ltd would prepare a flexible budget.",a:"Contribution is sales revenue less variable costs. This goes towards paying off the fixed costs. Once fixed costs are paid off, any further contribution goes towards profit.\n\nProfit is sales revenue less total costs (fixed and variable).\n\nWhy prepare a flexible budget:\n• To show management the cost levels at different levels of production.\n• To compare actual costs and budgeted costs at the same level of activity.\n• To compare budgeted costs and actual costs in order to identify variances — allowing corrective action.\n• To help in controlling costs or planning production levels. It is misleading to compare budgeted costs at one level of activity with actual costs at a different level."},
  {topic:"Budgeting",year:2020,marks:10,tags:["Cash Budget Advice","Master Budget"],q:"What useful information is available to Houghton Ltd from the cash budget? Explain what is meant by a master budget.",a:"In July and August the company has a maximum cash deficit of €110,920. The company needs to arrange a bank overdraft of €110,920 or take corrective action by leasing equipment (saving €12,000) or extending the period of credit received from one month to two months. The company could also try to get customers to buy more goods for cash rather than credit.\n\nThis shortfall is eliminated in September and October with a cash surplus at the end of October of €345,078. This could be used to purchase new fixed assets (increasing productive capacity) or purchase investments (increasing investment income and profit).\n\nMaster Budget: a summary of all the other budgets and provides an overview of the operations for the planned period. For example: a manufacturing budget, a sales budget, a cash budget."},
  {topic:"Budgeting",year:2021,marks:8,tags:["Sensitivity Analysis","Flexible Budget"],q:"(i) What is meant by the term sensitivity analysis? (ii) Outline why Henry Ltd would prepare a flexible budget.",a:"(i) Sensitivity Analysis is also known as 'what if' analysis. It is a technique used by management accountants to show the effect on profit brought about by changes in: (1) Selling price (2) Sales volume (3) Variable costs (4) Fixed costs.\n\n(ii) Why prepare a flexible budget:\n1. To show management the cost levels at different levels of production — it is misleading to compare budgeted costs at one level with actual costs at a different level.\n2. To compare actual costs and budgeted costs at the same level of activity to determine if actual costs exceeded or were less than budgeted.\n3. To compare budgeted and actual costs to identify variances — allowing corrective action.\n4. To help in controlling costs or planning production levels."},
  {topic:"Budgeting",year:2022,marks:10,tags:["Budgetary Control","Favourable Variance"],q:"(i) Outline why budgetary control is necessary in an organisation. (ii) In relation to budgets, explain what is meant by a favourable variance and give an example of how it might arise in the direct costs of a manufacturing firm.",a:"(i) Budgetary control is necessary to:\n1. Draw up a plan of performance — budgets are a roadmap for the business.\n2. Identify areas of responsibility to provide direction and motivation to staff to achieve targets.\n3. Identify future costs and revenues in order to plan cash inflows and outflows and control costs.\n4. Plan raw material requirements to ensure production levels can be achieved.\n5. Plan labour requirements to ensure adequate staffing levels in all areas.\n6. Ensure resources are used efficiently and to be capable of adapting to changing circumstances.\n7. Compare budgeted figures with actual figures and identify variances.\n\n(ii) A favourable variance occurs when actual costs are less than budgeted costs. It might arise in a manufacturing firm if:\n• The purchase price of raw materials is less than expected because of economies of scale, lower import charges or discount on early payments.\n• Less labour hours (lower wage costs) were required due to improved productivity.\n• Hire costs of special equipment is less than expected due to a surplus of equipment on the rental market.\n• Patent royalty costs are less than anticipated due to the patents coming close to their retirement date."},
  {topic:"Budgeting",year:2023,marks:8,tags:["Factors Affecting Sales","Cash Budget Advice"],q:"(i) What factors should be taken into consideration by Lupin Ltd in arriving at the expected sales figures for the first six months of 2024? (ii) On the basis of the cash budget you have prepared, what advice would you give to the management of Lupin Ltd?",a:"(i) Factors for sales estimate:\n• Market research / opinion of sales manager and sales representatives\n• Trends / State of the economy\n• Price to be charged / sales price\n• Competition\n• Luxuries versus necessities\n• Last year's sales from other stores\n\n(ii) Advice for Lupin Ltd:\n• There are serious cash shortages in February, March, April and May with a maximum forecast cash deficit at the end of March of €69,525 — even taking into account the €80,000 invested by the owners in January.\n• Lupin Ltd should change the credit terms for debtors to encourage more prompt payment by offering a bigger discount.\n• Lupin Ltd should hire equipment instead of buying it to reduce cash expenditure, spreading payments over the 5-year life of the asset rather than the 3-year repayment period for the loan. Delay the start date for repayment or repay over a longer period.\n• Agree better credit terms with creditors by negotiating a longer period of credit received.\n• Examine variable overheads to see if they can be reduced.\n• Examine the wage bill to see if it can be reduced.\n• Arrange a maximum bank overdraft of €69,525 — could be repaid quickly as by end of June there is a forecast cash surplus of €45,135."},
  // ═══ CASH FLOW (David Wilson 2001–2022) ═══
  {topic:"Cash Flow",year:2001,marks:8,tags:["Profit vs Cash"],q:"Explain why profit does not always mean a corresponding increase in cash.",a:"• Credit sales affect profit but do not affect cash.\n• Non-cash losses and gains affect profit but not cash.\n• Purchase and sale of fixed assets by cash affect cash but not profit.\n• Introduction or withdrawal of capital in cash affects cash but not profit."},
  {topic:"Cash Flow",year:2004,marks:10,tags:["Profit vs Cash","Non-Cash Items"],q:"Explain why profit does not always mean a corresponding increase in cash and list two non-cash items.",a:"• Credit sales/purchases affect profit but do not affect cash.\n• Non-cash losses and gains affect profit but not cash.\n• Purchase and sale of fixed assets by cash affect cash but not profit.\n• Introduction or withdrawal of capital in cash affects cash but not profit.\n\nNon-cash items: depreciation; provisions against losses; losses or profits from the sale of assets."},
  {topic:"Cash Flow",year:2006,marks:8,tags:["Purpose","Non-Cash Items"],q:"Explain why Cash Flow Statements are prepared. Identify a non-cash expense and a non-cash gain.",a:"Purposes:\n• To show the cash inflows and outflows during the past year.\n• To help predict future cash flows.\n• To help financial planning.\n• To provide information to assess liquidity.\n• To show that profits do not equal cash.\n• To comply with legal requirements.\n\nNon-cash expense: depreciation; increase in provision for bad debts.\nNon-cash gain: reduction in provision for bad debts; profit on sale of assets."},
  {topic:"Cash Flow",year:2008,marks:15,tags:["Profit vs Cash","Accounting Standards Board"],q:"Explain why earning profit does not always result in a corresponding increase in cash balances. Write a note on the Accounting Standards Board with reference to FRS 1 and Cash Flow Statements.",a:"Why profit ≠ cash:\n• Credit sales/purchases affect profit but do not affect cash.\n• Non-cash losses and gains affect profit but not cash.\n• Purchase and sale of fixed assets by cash affect cash but not profit.\n• Introduction or withdrawal of capital in cash affects cash but not profit.\n\nAccounting Standards Board: issues new accounting standards called Financial Reporting Standards (FRS). It also amends and withdraws old accounting standards.\n\nFRS 1 (issued by the ASB in 1991, revised 1996) requires large companies to prepare a Cash Flow Statement for each accounting period. It requires individual cash flows to be entered under standard headings according to the activity that gives rise to them."},
  {topic:"Cash Flow",year:2010,marks:12,tags:["Purpose","Cash vs Non-Cash Expense"],q:"Outline the benefits of preparing a Cash Flow Statement. Distinguish between a cash expense and a non-cash expense.",a:"Benefits:\n• Shows the cash inflows and outflows during the past year.\n• Shows that profits do not always equal cash.\n• Aids financial planning / used to predict future cash flows.\n• Provides information to assess current liquidity.\n\nCash expense — reduces both profit and cash, e.g. wages.\nNon-cash expense — reduces profit but not cash, e.g. depreciation, provision for bad debts."},
  {topic:"Cash Flow",year:2012,marks:12,tags:["Profit vs Cash","Directors' Responsibilities"],q:"Explain why earning profit does not always result in a corresponding increase in cash balances. Use figures from this question to support your answer. Outline two responsibilities of the Directors of a plc.",a:"Danton plc made an operating profit of €337,000 but the increase in cash for the year was €53,000.\n\nReasons:\n• Credit sales earn profit but do not increase cash — debtors increased by €200,000.\n• Non-cash gains/losses increase or decrease profit but not cash — profit on sale of buildings €13,000 / depreciation €72,000.\n• Sale/Purchase of fixed assets increases or decreases cash but not profit — receipts €101,000; payments €160,000 and €119,000.\n• Introduction/withdrawal of capital increases or decreases cash but not profit — receipts €220,000; payments €50,000.\n\nDirectors' responsibilities:\n• Comply with the Companies Acts.\n• Keep proper accounting records enabling financial statements to be prepared.\n• Prepare annual financial statements.\n• Select suitable accounting policies.\n• Sign financial statements.\n• Safeguard the assets of the company.\n• Publish Final Accounts and Cash Flow Statement at least once a year.\n• Present an Annual Report to shareholders at AGM (Directors' report, Auditor's Report, Financial Statements)."},
  {topic:"Cash Flow",year:2014,marks:9,tags:["Profit vs Cash","Companies Act"],q:"Explain the reasons why Doyle plc, who has an operating profit of €185,000, has generated a greater net cash inflow from operating activities. List three accounting obligations of a large public company under the Companies Act.",a:"Doyle plc has generated €59,000 (€244,000 − €185,000) more cash inflow during the year because:\n• Depreciation €60,000 and loss on sale of machinery €25,000 reduced profit but had no effect on cash inflow.\n• An increase in creditors during the year increased cash inflow by €5,000 but has nil effect on profit.\n• The increase in debtors and stock during the year of €8,000 and €23,000 respectively contributed to a reduction in net cash inflow but have no effect on profits.\n\nAccounting obligations of a large public company:\n• Provide a full set of accounts, balance sheet and cash flow statement to shareholders at the AGM.\n• File/register a full set of accounts and balance sheet with the Registrar of Companies.\n• Provide explanatory notes to these accounts.\n• Must have its accounts audited.\n• Present an annual report at the AGM including a directors' report, an auditor's report and the published accounts."},
  {topic:"Cash Flow",year:2015,marks:12,tags:["Purpose","Decline in Cash"],q:"Outline the purposes of cash flow statements. Explain, why having earned a profit during 2014, the company's cash balance declined.",a:"Purposes:\n• To show that profits do not always equal cash.\n• To show the cash inflows and outflows during the past year.\n• To help predict future cash flows.\n• To help financial planning.\n• To provide information to assess liquidity / solvency.\n• To comply with legal requirements.\n• To aid application for loans.\n\nWhy cash balance declined:\n• Purchase of fixed assets reduced cash by €220,000 but did not reduce profit.\n• Purchase of Government securities reduced cash by €56,000 but did not reduce profit.\n• Payment of dividends €55,000 and tax €57,000 reduced cash by €112,000 but did not reduce profit.\n• Increase in stock, debtors and decrease in creditors reduced cash by €148,000 but did not reduce profit."},
  {topic:"Cash Flow",year:2019,marks:12,tags:["Non-Cash Items","Cash but not Profit"],q:"(i) Explain what is meant by a non-cash item. Give three examples, using the figures provided. (ii) Explain two items that affect cash but not profit.",a:"(i) Non-cash items are items in the profit and loss account that affect the net profit but do not affect the cash situation.\nE.g. depreciation €72,000; increase in bad debt provision €400; goodwill written off €11,000; loss on sale of fixed asset €1,700.\n\n(ii) Items that affect cash but not profit:\n• The purchase of fixed assets decreases cash but does not affect profit.\n• The sale of fixed assets increases cash but does not affect profit.\n• The introduction of capital increases cash but not profit.\n• Drawings reduce cash but have no effect on profit.\n• Loans received or repaid (loans received increase cash but do not affect profit).\n• Investments bought or sold."},
  {topic:"Cash Flow",year:2021,marks:24,tags:["Profit vs Cash","Purpose"],q:"(b)(i) Explain why earning profit may not always result in a corresponding increase in cash balances. Use figures from this question to support your answer. (ii) Outline reasons why Reid plc would prepare a cash flow statement.",a:"(i) Profit, but not cash:\n1. Credit sales increase profit but do not increase cash — debtors increased by €70,000.\n2. Profit on disposal of fixed assets increases profit by €18,000 but does not increase cash by the same amount.\n3. Depreciation on fixed assets of €34,000 reduces profit but does not reduce cash.\n4. Patents written off €9,000 reduces profit but does not reduce cash.\n5. Increase in bad debts provision of €3,400 reduces profit but does not reduce cash.\n\nCash, but not profit:\n6. Receipts from sale of fixed assets €90,000 increase cash but have no immediate effect on profit.\n7. Payments for the purchase of fixed assets €330,000 reduce cash but have no immediate effect on profit.\n8. Receipts from issue of shares and premium €180,000 increase cash but have no immediate effect on profit.\n9. Payments to redeem debentures €50,000 reduce cash but have no immediate effect on profit.\n\n(ii) Why prepare a cash flow statement:\n1. To show cash inflows and cash outflows during the year.\n2. To assist in predicting future cash flows.\n3. To aid financial planning.\n4. To provide information for assessing liquidity.\n5. To highlight that profit does not always equal cash.\n6. To assist in applications for loans from financial institutions.\n7. To comply with Company Law."},
  {topic:"Cash Flow",year:2022,marks:8,tags:["Financial Reporting Standard","Cash vs Non-Cash Gain"],q:"(i) Financial Reporting Standard 1 requires companies to prepare a cash flow statement. What is a Financial Reporting Standard? (ii) Distinguish between a cash gain and a non-cash gain for Puspure plc. Give one example of each.",a:"(i) A Financial Reporting Standard is a rule that must be applied to all financial statements in order to give a true and fair view of the company's financial position. It sets out best practice in accounting that allows accounts to be compared from year to year and from company to company.\n\n(ii) A cash gain — increases profit AND cash, e.g. investment income €3,700.\nA non-cash gain — increases profits but not cash, e.g. profit on sale of fixed asset €1,000."},
  // ═══ CLUB ACCOUNTS (David Wilson 2002–2022) ═══
  {topic:"Club Accounts",year:2002,marks:15,tags:["Reduce Subscriptions"],q:"Indicate the points you, as Treasurer, would make to a proposal by the members at the AGM to reduce subscriptions by 10%.",a:"A reduction in subscriptions of 10% for 2002 would involve a reduction in club income of €6,650.\n\nThe club is capable of bearing such a decrease based on the surplus of income for 2001. However, almost all of this surplus is provided by entrance fees of €16,000 and sponsorship of €36,000.\n\nThe treasurer might refer to proposed capital expenditure on the club in the near future.\n\nAlthough the club has a healthy bank balance of €30,490 and investments of €70,000, these funds are not of a recurring nature and even the sponsorship may not be guaranteed in future years.\n\nIt would NOT be prudent to reduce subscription fees at present. Instead it would be advisable to retain the present level of fees and use these fees to provide improved facilities for the members and thus attract more members."},
  {topic:"Club Accounts",year:2004,marks:15,tags:["Reduce Subscriptions"],q:"Indicate the points you, as treasurer, might make if the members at the AGM of the club proposed to reduce the annual subscription by 20%.",a:"A reduction in subscriptions of 20% for 2004 would involve a reduction in club income of €36,000.\n\nAlthough the club is financially sound — it has €5,190 in the bank, €70,000 in the building society, investments worth €40,000 and has paid off a loan of €30,000 — these funds are set aside for future capital expenditure.\n\nThe club's surplus of income for 2003 of €50,015 would seem to indicate that the club is capable of bearing a reduction of 20%. However, almost all of this surplus is provided by entrance fees of €17,000 and sponsorship of €33,000 — income that cannot be guaranteed in future years.\n\nIt can be argued that a reduction in membership fees could attract more members and thus bring in entrance fees as well as increased bar profit. However it would NOT be prudent to reduce subscription fees at present. Instead retain the present level of fees and use these fees to provide improved facilities for the members and thus attract more members."},
  {topic:"Club Accounts",year:2008,marks:10,tags:["Special Purpose P&L","Levy"],q:"Explain with the use of an example what is meant by a Special Purpose Profit & Loss Account. If it were proposed to introduce a further four year levy to fund a €250,000 extension what points would you as an ordinary member now make.",a:"Special Purpose P&L: sometimes non-profit-making organisations such as a club prepare a Profit and Loss account for activities that are carried out to make a profit, e.g. running a club lottery, dances, bar, restaurants etc. All expenses and revenues relating to that particular activity are entered in a special profit and loss account and the profit is then transferred to the income and expenditure account.\n\nThe proposed levy would raise €200,000 over 4 years (250 × €200 × 4).\n\nAs a member I would make the case that the club is capable of generating enough income from within as it has a surplus of income of €63,180. The club is financially sound — cash of €13,960, building society investment of €60,000 and 5% government investments €24,000 totalling €97,960 — even after it has paid off a loan and interest of €33,600 and purchased equipment for €45,000.\n\nHowever a sizeable proportion of the surplus is provided by Entrance Fees of €15,000 and Sponsorship of €25,000. This income cannot be guaranteed in future years."},
  {topic:"Club Accounts",year:2011,marks:15,tags:["Receipts & Payments Limitations","Floodlights"],q:"State and explain two limitations of a Receipts and Payments Account. The club is considering the installation of floodlights at a cost of €70,000. What advice would you give to the Treasurer of the club?",a:"Limitations of a Receipts and Payments Account:\n• Does not show whether the club is raising enough funds to cover its running costs.\n• Amounts due but unpaid at the end of the accounting period are not included.\n• Only shows an increase or decrease in cash although there could be outstanding bills.\n• Does not take into account losses such as depreciation.\n• Does not show whether the club bar or restaurant are profitable.\n• Does not distinguish between receipts for the current year and other years.\n\nFloodlights advice — YES, I would advise the treasurer to go ahead. Improved facilities would allow longer use of club courts resulting in added income from usage. This could enable the club to increase its membership and thereby increase the annual surplus of income, as well as greater usage of restaurant and bar.\n\nThe club is in a strong financial position: surplus of income over expenditure of €34,894; bank balance of €45,180 after paying off a loan of €30,000 during the year (includes levy €20,000). At this rate of surplus enough funds would be generated in little over two years.\n\nTo fund the expenditure of €70,000 the club could use the cash balance of €45,180, the prize bonds of €4,400 and withdraw €20,420 from the investment fund. The club should avoid using any of the funds raised through the levy as this is more than likely earmarked for other purposes.\n\nFunds available without Reserve Fund: Investments €50,000 + Prize bonds €4,400 + Bank balance €45,180 = €99,580. Less Levy (€40,000) = Net available €59,580. Borrow the remainder in the short term."},
  {topic:"Club Accounts",year:2013,marks:10,tags:["Special Purpose P&L","Levy"],q:"Explain with the use of an example what is meant by a Special Purpose Profit & Loss Account. The club has decided to lay an all-purpose floor at a cost of €150,000. The Treasurer has proposed to increase the levy by €120 per annum and extend it for five more years. As an ordinary member what arguments would you make against this proposal?",a:"Special Purpose P&L: sometimes non-profit-making organisations such as a club prepare a profit and loss account for activities that are carried out to make a profit e.g. running a club lotto, dances, bar, restaurant. All expenses and revenues relating to the particular activity are entered in a special purpose P&L account and the profit/loss is then transferred to the income and expenditure account.\n\nThe proposed levy would raise €150,000 over 5 years (200 × €150 × 5).\n\nFunds available: Investments €30,000 + Building society €28,000 + Cash €4,310 = €62,310.\n\nArguments against:\n• The proposed levy of €200 (€120 + €80) amounts to 66% of the annual subscription. An increased levy would discourage new members and perhaps cause a drop in membership.\n• The club is capable of generating enough income from within — surplus of income of €69,099; financially sound with €62,310 in cash + investments.\n• Although a sizeable proportion of the surplus is provided by sponsorship of €73,000 (not guaranteed), this is well below the non-recurring capital amounts paid this year (equipment €41,000 + loan €44,800 = €85,800).\n• Alternative: use the cash and investments totalling €62,310 and borrow approx €90,000; OR continue with current levy of €80 for 5 years plus use current funds and borrow approx €28,000.\n• The improved facilities could increase rent earned from the arena, increase membership, and encourage increased advertising income."},
  {topic:"Club Accounts",year:2016,marks:8,tags:["Levy","Life Membership"],q:"Distinguish between 'levy' and 'life membership'. Explain how both are treated in the accounts.",a:"Levy: a payment made to a club by its members to fund a special project such as a clubhouse extension. It must be used for the purpose for which it is collected. It is a capital receipt (on a once-off basis or for a specific number of years) and is credited to a reserve fund. It is due to the members until it is used, so it is treated as a long-term liability in the balance sheet.\n\nLife Membership: where a club member pays a fee that entitles her/him to use the facilities of the club for the rest of her/his life. It is treated as a long-term liability in the balance sheet and can be written off to income over a stated number of years."},
  {topic:"Club Accounts",year:2019,marks:10,tags:["Funding Options"],q:"The club would like to build a new driving range at a cost of €350,000. Outline the options available to the club in funding this project with reference to the accounts.",a:"Funding options:\n\nSales of investments €67,500\nBank balance €83,300\nTotal €150,800\nLess levy (€60,000)\nNet available €90,800\n\n1. Investments can be sold which would realise €67,500.\n2. They have a very healthy bank balance of €83,300 and would have no problem meeting interest repayments. They could fund this extension by borrowing the remainder of €259,200 without having to touch their levy reserve fund. A loan could be obtained as the club is a profitable concern with more than adequate security in the form of its clubhouse and course.\n3. Based on financial results for 2018, the club had a surplus of income of €65,180 — when added to depreciation of €18,450 (non-cash item) this indicates a cash inflow from operating activities of around €83,630. The club is very capable of repaying a loan. They have also repaid a loan with interest of €20,900, bought equipment of €15,000, and transferred €10,000 from their building society.\n4. A sizeable part of their surplus, €34,900 of the income, is coming from annual sponsorship, entrance fees and lottery funding. These are not guaranteed as a source of income."},
  {topic:"Club Accounts",year:2022,marks:10,tags:["Special Purpose P&L","Reduce Subscriptions"],q:"(i) Explain with the use of an example what is meant by a Special Purpose Profit & Loss Account. (ii) There is a proposal to reduce annual subscriptions by 10% for the next three years. As Treasurer of Abbey Hockey Club, what points would you make in favour of this proposal?",a:"(i) Special Purpose P&L Account: many not-for-profit organisations run activities to raise funds for the organisation. These activities are intended to generate profits to invest in the organisation. The expenses and revenues relating to that particular activity are entered in a 'special profit and loss account' and the profit is then transferred to the income and expenditure account. Examples: running a bar, restaurant, lotto, or a dance.\n\n(ii) The proposal to reduce subscriptions by 10% will reduce income by €35,534 per year based on current subscriptions.\n\nPoints in favour:\n• The club is in a healthy financial position with a bank balance of €239,170 — considerably higher than the bank balance at the beginning of the year (€9,800). Excluding the once-off grant of €120,000 this is still very healthy.\n• They have investments of €25,200.\n• They have paid back a loan with interest of €273,480 in total.\n• Current surplus income of €329,845 will reduce to €294,291 with the reduction of €35,534 in subscriptions — still a very healthy surplus.\n• This may bring in extra members which may counteract the reduction in the subs rate and result in revenue remaining the same.\n• The club has net expenditure on fixed assets of €40,000 which it may not have in the coming years.\n• The club is well able to financially sustain a reduction in the subscription fee of 10%."},
  // ═══ CORRECTION OF ERRORS (David Wilson 2006–2022) ═══
  {topic:"Correction of Errors",year:2006,marks:10,tags:["Error of Commission","Error of Principle"],q:"Explain with examples the difference between 'error of commission' and 'error of principle'.",a:"Error of commission: occurs when the correct amount is posted to the correct side of the incorrect account. E.g. goods sold on credit to Pat O'Brien debited in error to John O'Brien's account.\n\nError of principle: arises when an item is posted to the incorrect class of account. E.g. an electrical shop owner purchased a vehicle and entered it in the purchases account instead of the vehicles account."},
  {topic:"Correction of Errors",year:2008,marks:10,tags:["Error of Commission","Error of Principle"],q:"Explain with examples what is meant by: (i) Error of Commission; (ii) Error of Principle.",a:"(i) Error of commission: occurs when the correct amount is posted to the correct side of the incorrect account. Example: goods sold on credit to Brian Brady debited in error to John Brady's account.\n\n(ii) Error of principle: arises when an item is posted to the incorrect class of account. Example: a boutique owner purchased a vehicle and treated it as a purchase of stock."},
  {topic:"Correction of Errors",year:2010,marks:10,tags:["Errors Affecting Trial Balance"],q:"Identify three different types of errors that affect the balancing of a Trial Balance.",a:"• Entering one amount on the debit side of one ledger account and entering a different amount on the credit side of another ledger account.\n• Mathematical errors — figures and additions.\n• Posting only one side of the double entry."},
  {topic:"Correction of Errors",year:2012,marks:6,tags:["Trial Balance Purpose","Errors Not Revealed"],q:"What is the purpose of preparing a Trial Balance? State and explain two types of errors not revealed by the Trial Balance.",a:"A Trial Balance is prepared in order to test the accuracy of double-entry bookkeeping before preparing Final Accounts. A Trial Balance should have the same total of debits and credits because under double-entry bookkeeping every debit entry should have a corresponding credit entry.\n\nErrors not revealed by a trial balance:\n• Errors of original entry — errors made in books of first entry.\n• Errors of principle — incorrect class of account (e.g. entering an asset in an expense account).\n• Errors of complete omission — where both debit and credit are omitted.\n• Errors of commission — posting to wrong account but to the correct side of correct type of account.\n• Compensating errors — where errors of equal value cancel each other out.\n• Reversal of entries — where the debit entry is on the credit side and the credit entry is on the debit side."},
  {topic:"Correction of Errors",year:2014,marks:6,tags:["Errors Affecting Trial Balance"],q:"Identify three types of errors that affect the balancing of a Trial Balance.",a:"• Errors in figures and addition.\n• Posting only one side of the double entry.\n• Entering one amount on the debit side of one ledger account and entering a different amount on the credit side of another ledger account."},
  {topic:"Correction of Errors",year:2016,marks:6,tags:["Compensating Errors","Errors of Original Entry"],q:"Explain: (i) Compensating errors. (ii) Errors of original entry.",a:"(i) Compensating errors: where an error on the debit side of one account is compensated by another error of an equal amount on the credit side of another account. For example, a cash payment of €550 for repairs entered as €55 on the debit of the repairs account and on the credit side of the cash account.\n\n(ii) Errors of original entry: errors made in the books of first entry which are then subsequently posted to the appropriate ledger accounts. For example, credit purchases from T. Long €223 entered as €322 in the purchases book and posted accordingly to both the purchases account and to Long's account."},
  {topic:"Correction of Errors",year:2018,marks:6,tags:["Suspense Account"],q:"Outline the purpose of a suspense account.",a:"A suspense account is used when there is a mistake in the accounts that prevents the trial balance from balancing.\n\nThe difference between the debit and credit side of the trial balance is entered in the suspense account, until the errors are discovered, in order to allow the trial balance to balance. The relevant errors are corrected through the suspense account and the balance is then eliminated."},
  {topic:"Correction of Errors",year:2020,marks:8,tags:["Error of Commission"],q:"Give an example of an error of commission. Will this type of error be revealed by a trial balance? Explain your answer.",a:"Error of commission: where the correct amount is posted to the correct side of the incorrect account. For example, sales of €5,000 debited to M O'Flaherty's account instead of D O'Flaherty.\n\nThis will NOT be revealed by the trial balance as the correct amount has been entered on the debit side even though in the wrong account. The debit side and credit side of the trial balance will agree so it will not be obvious that an error has been made."},
  {topic:"Correction of Errors",year:2022,marks:8,tags:["Trial Balance Purpose","Errors Affecting Trial Balance"],q:"(i) What is the purpose of preparing a trial balance? (ii) Outline different types of errors that may affect the balancing of the trial balance.",a:"(i) A Trial Balance is prepared to test/check the accuracy of double-entry bookkeeping before preparing the Income Statement (Final Accounts) and the Statement of Financial Position (Balance Sheet). A Trial Balance should have the same total of debits and credits because under double-entry bookkeeping every debit entry should have a corresponding credit entry.\n\n(ii) Errors that may affect the balancing of the trial balance:\n1. Entering one figure on one side of a ledger account but a different figure on the other side of another ledger account.\n2. Entering one figure on one side of a ledger account but any figure on the same side of another ledger account.\n3. Entering one figure on one side of a ledger account but entering nothing on the other side of another ledger account.\n4. Mathematical errors / errors of calculation, addition, subtraction in totalling or closing off."},
  // ═══ COSTING (David Wilson 2003–2023) ═══
  {topic:"Costing",year:2003,marks:12,tags:["Product Costing"],q:"State two reasons for product costing and explain each.",a:"• To establish the selling price for the purpose of tendering.\n• To control costs — budget versus actual.\n• To help planning and decision making.\n• To ascertain the value of closing stock in order to prepare final accounts."},
  {topic:"Costing",year:2004,marks:10,tags:["Marginal Costing Limitations"],q:"List and explain two limitations/assumptions of marginal costing.",a:"• Variable costs are assumed to be completely variable at all levels of output. However variable costs may decrease due to economies of scale or may increase because of increased costs.\n• It is assumed that in marginal costing fixed costs remain the same although most fixed costs are step-fixed and are only fixed within a relevant range.\n• It is assumed that all mixed costs are easily separated into fixed or variable. The High-Low method can be used for this but it is not always possible.\n• It is assumed that the selling price per unit is constant and does not allow for discounts.\n• Production in a period usually equals sales — fixed costs are charged in total to a period and are not carried forward to the next period."},
  {topic:"Costing",year:2005,marks:8,tags:["Overhead Absorption Rates"],q:"Name three overhead absorption rates and state why they are based on budgeted rather than actual figures.",a:"Absorption rates:\n• Per Labour Hour\n• Per Machine Hour\n• Per Unit\n• Percentage of Prime Cost\n\nOverhead absorption rates are based on budgeted rather than actual costs because actual costs may not be known until the end of the year and the business cannot wait until then to decide the cost of the product as they need to decide on the selling price to charge."},
  {topic:"Costing",year:2006,marks:12,tags:["Marginal vs Absorption Costing"],q:"Outline the differences between Marginal and Absorption costing. Indicate which method should be used for financial accounting purposes and why.",a:"There is a different profit figure because closing stock is valued differently. Marginal costing does NOT include fixed costs when costing a product whereas absorption costing does include the fixed costs. Therefore closing stock under marginal costing is valued lower than under absorption costing because a share of fixed costs is included in the value of stock under absorption costing but not included under marginal costing.\n\nUnder absorption costing, closing stock is valued at ¼ of the production cost of 17,400.\nUnder marginal costing, closing stock is valued at ¼ of the production cost of 14,400.\n\nClosing stock — Absorption costing 4,350\nClosing stock — Marginal costing (3,600)\nDifference 750\nThe profit difference is 22,950 − 22,200 = 750.\n\nAbsorption costing should be used as it agrees with standard accounting practice and concepts and matches costs with revenues."},
  {topic:"Costing",year:2007,marks:8,tags:["Re-apportionment","Over-absorption"],q:"Explain what is meant by 're-apportionment' of overheads. Illustrate and explain 'over-absorption' of overheads.",a:"Re-apportionment: the term used where Service Department costs are re-apportioned between production departments because overheads can only be recovered by being included as part of the cost of production.\n\nOver-absorption: when costs are over-recovered — budgeted costs are greater than actual costs. E.g. the cost of fuel/power reduced."},
  {topic:"Costing",year:2008,marks:6,tags:["Contribution Sales Ratio"],q:"For what purpose is the Contribution Sales Ratio regularly used? When is the use of this ratio essential?",a:"• To calculate the break-even point.\n• When necessary figures are not available — variable cost or selling price or units."},
  {topic:"Costing",year:2009,marks:10,tags:["Step Fixed Cost","Management vs Financial Accounting"],q:"Explain what is meant by a step fixed cost and give an example. Outline two differences in focus between Management and Financial accounting.",a:"Step fixed costs are costs that are fixed within a certain range of activity but change outside of that range. E.g. rent could be fixed up to a certain level of production. However, if production increases and results in the rental of more factory space, then the rent would increase to a new level. Thus the fixed costs would increase in steps.\n\nManagement vs Financial Accounting:\n• Management accounting is concerned with planning for the future (information for planning and budgeting); financial accounting is concerned with recording past events (P&L, balance sheet, cash flow statement).\n• Management accounting has an internal focus (information to aid planning and decision making); financial accounting has both internal and external focus (information to stakeholders such as managers, shareholders and creditors).\n• Management accounting is not governed by legislation; financial accounting is governed and regulated by both legislation and accounting standards such as FRSs.\n• Management accounting reports prepared as often as managers require; financial accounting reports usually once a year.\n• Management accounting reports prepared for cost centres / departments; financial accounting reports about the whole business."},
  {topic:"Costing",year:2011,marks:15,tags:["Marginal Costing Limitations","Step Fixed Cost"],q:"List and explain two limitations/assumptions of marginal costing. Explain what is meant by a step fixed cost and roughly sketch a graph of step fixed costs.",a:"Limitations/assumptions of marginal costing:\n• Variable costs are assumed to be completely variable at all levels of output. However variable costs may decrease due to economies of scale or may increase because of increased costs.\n• It is assumed that fixed costs remain the same although most fixed costs are step-fixed and are only fixed within a relevant range.\n• It is assumed that all mixed costs are easily separated into fixed or variable (the High-Low method can be used but it is not always possible).\n• It is assumed that the selling price per unit is constant and does not allow for discounts.\n• Production in a period usually equals sales. Fixed costs are charged in total to a period and are not carried forward to the next period.\n\nStep Fixed Cost: a cost that is fixed within a certain range of activity but changes outside that range. E.g. rent could be fixed up to a certain level of production. However, if production increases and results in the rental of more factory space, the rent would increase to a new level. Thus the fixed costs would increase in steps."},
  {topic:"Costing",year:2012,marks:5,tags:["Service Department Costs"],q:"Explain why it is necessary to transfer Service Department costs to Production Departments 1 and 2.",a:"Service departments can't recover costs. Service departments are secondary to production departments and as a result, service department costs must be transferred to production departments on an equitable basis e.g. machine hours. Overheads can only be recovered through production — i.e. they are included as a cost of production."},
  {topic:"Costing",year:2013,marks:8,tags:["Under/Over Absorption"],q:"Show the under/over absorption by department and in total for the period. Explain what these figures mean.",a:"In Department A, the costs incurred were €10,000 less than expected/budgeted and therefore profits are €10,000 greater than expected.\nIn Department B, the costs incurred were €1,000 more than expected/budgeted and therefore profits are €1,000 less than expected.\nIn Department C, the costs incurred were €6,700 less than expected/budgeted and therefore profits are €6,700 greater than expected.\nOverall, the costs incurred were €15,700 less than expected/budgeted and therefore profits are €15,700 greater than expected."},
  {topic:"Costing",year:2014,marks:9,tags:["Marginal vs Absorption Costing"],q:"Outline the differences between Marginal and Absorption costing. Indicate which method should be used for financial accounting purposes and why.",a:"There is a difference in profit figures because closing stock is valued differently. Closing stock under marginal costing is valued lower than under absorption costing. When costing a product, marginal costing does not include fixed costs whereas in absorption costing the fixed costs are included. Therefore a share of fixed costs is included in the value of stock under absorption costing and not included under marginal costing.\n\nUnder absorption costing, closing stock is valued at 1/10 of the production cost of €19,000.\nUnder marginal costing, closing stock is valued at 1/10 of the variable cost of €15,000.\nClosing Stock — Absorption Costing 1,900\nClosing Stock — Marginal Costing (1,500)\nDifference 400\nThe profit difference is 18,900 − 18,500 = 400.\n\nAbsorption costing should be used as it agrees with standard accounting practice and concepts and also matches costs with revenues."},
  {topic:"Costing",year:2015,marks:6,tags:["Stock Valuation"],q:"Outline the implications of an incorrect stock valuation.",a:"Incorrect valuation of stock affects:\n• The Financial Statements of two years/two accounting periods — the closing stock of one accounting period and the opening stock of the next.\n• The figures for cost of sales, gross profit, net profit and subsequently figures in the balance sheet.\n• In the balance sheet it will affect the figures for current assets and working capital / net assets.\n• In carrying out ratio analysis the figure for stock will affect the stock turnover, percentage mark-up on cost, gross profit percentage, net profit percentage and the current ratio.\n• The opinion of the firm in financial circles, its tax liability, its ability to borrow, public opinion and consequently its share price.\n\nThe mark-up on cost in an industry provides a valuable measure for any firm in that industry. A mark-up that is out of line with the norm is a cause for concern and should lead to immediate investigation. Stock turnover determines the total volume of profit — therefore the higher the better."},
  {topic:"Costing",year:2016,marks:8,tags:["Re-apportionment","Overhead Absorption Rates"],q:"Explain what is meant by reapportionment of overheads. Name three overhead absorption rates and state why they are based on budgeted figures.",a:"Re-apportionment of costs: the term used where service department costs are reapportioned/divided between production departments because overheads can only be recovered by being included in the cost of production.\n\nAbsorption rates: per labour hour; per machine hour; per unit; percentage of prime cost.\n\nOverhead absorption rates are based on budgeted rather than actual costs because actual costs may not be known until the end of the year and the business cannot wait until then to decide the cost of the product as they need to decide on the selling price to charge for tendering purposes."},
  {topic:"Costing",year:2017,marks:5,tags:["Sensitivity Analysis"],q:"What is meant by the term 'Sensitivity Analysis'?",a:"Sensitivity Analysis is also known as 'what if' analysis. It is a technique used by management accountants to show the effect on profit brought about by changes in:\n1. Selling price\n2. Sales volume\n3. Variable costs\n4. Fixed costs"},
  {topic:"Costing",year:2018,marks:10,tags:["Prudence","Management Accountant Role"],q:"Explain how the concept of prudence applies to the valuation of closing stock. Outline the role of the management accountant within an organisation.",a:"The prudence concept states that caution should be exercised when preparing financial statements. Therefore, only realised profits should be included in the accounts. However, provision should be made for all expected expenses and losses. The prudence concept ensures that profits are not overstated and losses not understated. If closing stock was overvalued then profits would be overstated. Therefore stocks should be valued at the lower of cost or net realisable value.\n\nThe management accountant is a key member of an organisation's management team who makes a vital contribution to the managerial functions of planning, controlling and decision making.\n\nResponsibilities:\n1. Preparing data / gathering information required for formulating plans.\n2. Recording costs and providing details of the cost of products and departments.\n3. Participation in the creation and execution of budgets.\n4. Assisting in the control of operations by comparing actual costs with budgeted costs.\n5. Providing data for decisions that require managers to select between alternative courses of action.\n6. Ensuring that relevant data is provided to managers on a timely basis and that the data is readily understandable.\n7. The valuation of closing stock which is then used in the preparation of financial statements."},
  {topic:"Costing",year:2019,marks:10,tags:["Service Departments","Allocation Apportionment Absorption","Product Costing"],q:"(i) Explain why it is necessary to transfer service department overheads to production departments. (ii) Distinguish between the allocation, apportionment and absorption of costs. (iii) Explain three reasons for product costing.",a:"(i) Service departments cannot recover costs because no production takes place in these departments. They are secondary to production departments and as a result service department costs must be transferred to production departments on an equitable basis e.g. machine hours. Overheads can only be recovered through production.\n\n(ii) Allocation: where overhead costs can be specifically identified and charged to a particular department or cost centre.\nApportionment: where overheads cannot be specifically identified but are shared or divided between departments using an appropriate basis.\nAbsorption: the method by which costs are charged to cost units/units of products in order to be recovered. An overhead absorption rate for each department can be calculated using a suitable basis such as rate per unit, per labour hour and per machine hour.\n\n(iii) Reasons for product costing:\n1. Establishes the selling price for tendering purposes.\n2. Controls costs by comparing budgeted costs with actual costs.\n3. Helps with planning and decision making.\n4. To find the value of closing stock to be used when calculating profit."},
  {topic:"Costing",year:2020,marks:10,tags:["Step Fixed Cost","Marginal vs Absorption Costing"],q:"Explain what is meant by a step fixed cost and give an example. Outline the differences between marginal and absorption costing. Indicate which method should be used for financial accounting purposes. Explain your answer.",a:"Step fixed costs are costs that are fixed within a certain range of activity but change outside of that range. E.g. rent could be fixed up to a certain level of production. However, if production increases and results in the rental of more factory space, the rent would increase to a new level. Thus, the fixed costs would increase in steps.\n\nMarginal v Absorption Costing: a different profit figure arises because closing stock is valued differently. Marginal costing does not include fixed costs when costing a product whereas absorption costing does. Therefore closing stock under marginal costing is valued lower because a share of fixed costs is included in the value of stock under absorption costing but not under marginal.\n\nUnder absorption costing, closing stock is valued at 20% of the production cost of €36,150 = €7,230.\nUnder marginal costing, closing stock is valued at 20% of the variable cost of €27,750 = €5,550.\nDifference = €1,680. The profit difference is €21,480 − €19,800 = €1,680.\n\nAbsorption costing should be used as it agrees with standard accounting practice and concepts and matches costs with revenues."},
  {topic:"Costing",year:2022,marks:10,tags:["Overhead Absorption","Under-absorption"],q:"(i) Explain why overhead absorption rates are based on budgeted costs rather than actual costs. (ii) Explain 'under-absorption' of overheads and how it might arise in a manufacturing firm.",a:"(i) Overhead absorption rates are based on budgeted costs rather than actual costs because the product needs to be costed at the time of order but actual costs may often not be known until the end of the year. A business cannot wait until then to set the selling price of a product for a customer.\n\n(ii) Under-absorption is when costs are under-recovered — budgeted costs are less than actual costs. This may be due to:\n1. Actual labour hours used in the manufacturing process could be higher than budgeted for.\n2. There could have been errors in estimating overheads.\n3. Overhead expenses are higher due to unforeseen events e.g. oil prices higher on world markets or depreciation of assets higher than estimated.\n4. Unexpected changes in method of production causing higher than expected prices e.g. more fuel required to power machines.\n5. Cleaning costs have increased due to wages of staff increasing because of inflation.\n6. Light and heat costs have increased due to oil and gas prices rising.\n7. Insurance costs have increased due to higher premiums as a result of higher risks.\n8. Transport costs have increased due to diesel prices increasing.\n9. Depreciation expenses have increased due to higher expenditure on fixed assets."},
  {topic:"Costing",year:2023,marks:7,tags:["Absorption Costing Benefits"],q:"Outline the benefits of absorption costing.",a:"1. All costs, variable and fixed, are recovered in the selling price charged to customers.\n2. It gives a more accurate valuation of closing stock at the end of the financial period and this will enable accurate final accounts to be prepared.\n3. Helps managers to calculate the total cost of producing each product, which enables a business to manufacture the most profitable products.\n4. There is no need to separate costs into variable and fixed costs which can be very time-consuming and costly, and in many cases may not be possible at all.\n5. Absorption costing complies with accounting principles and standards.\n6. It matches the costs and revenues for the period.\n7. Profit is higher under absorption costing."},
  // ═══ DEPRECIATION (David Wilson 2022) ═══
  {topic:"Depreciation",year:2022,marks:8,tags:["Straight Line","Reducing Balance","Method Selection"],q:"(i) Distinguish between the straight line method and reducing balance method of depreciation. (ii) Why would a company choose one method of depreciation over another?",a:"(i) Straight Line Method: the same amount of the cost of the asset is written off each year. Appropriate for an asset that remains in the business over a long period of time and loses value slowly, e.g. buildings that generate profit over many years. The straight-line method involves spreading the depreciable amount evenly over the estimated useful life of the asset. Using this method, the depreciation is the same figure each year, which suggests that the asset is being used up at an even rate.\n\nReducing Balance (Diminishing Balance) Method: applies a constant percentage to the gradually reducing carrying amount balance so that the amount of depreciation expense diminishes over the useful life of the asset. The amount written off is high in early years and reduces each year until written off. Appropriate for an asset which loses most of its value in the years immediately after purchase, e.g. vehicles, computers, equipment (assets that become obsolete quickly because of changes in technology). Relatively few businesses use the reducing balance method and, where it is used, the percentage figure is often an approximation.\n\n(ii) A method of depreciation is chosen by a company depending on the type of the asset and its policy on depreciation, ensuring that the consistency concept is applied when preparing accounts."},
  // ═══ FARM ACCOUNTS (David Wilson 2006–2020) ═══
  {topic:"Farm Accounts",year:2006,marks:8,tags:["Reasons for Accounts"],q:"Give three reasons why farmers should keep a full set of accounts.",a:"• To find out the profit of the farm.\n• To find out the net worth of the farm.\n• To find out the profit of each section of the farm.\n• To back up applications for grants and bank loans.\n• To facilitate planning / budgeting."},
  {topic:"Farm Accounts",year:2009,marks:3,tags:["Farm Produce Used by Family"],q:"Which account, other than drawings, is affected by 'farm produce used by family'? Explain your answer.",a:"Drawings are debited and Sales are credited. Sales are credited instead of purchases because the farm produce is produced rather than purchased."},
  {topic:"Farm Accounts",year:2012,marks:3,tags:["Reasons for Accounts"],q:"Farmers prepare accounts to ascertain net profit. For what other purposes do they prepare accounts?",a:"• To establish the performance of each section of the farm for comparative purposes.\n• To back up applications for bank loans and specific grants.\n• To ascertain tax liability.\n• To facilitate planning / budgeting.\n• To find out the net worth of the farm.\n• To find out the amount owed by and owed to the farmer."},
  {topic:"Farm Accounts",year:2015,marks:5,tags:["General P&L","Enterprise Analysis"],q:"For what purposes does a farmer prepare a General Profit & Loss Account? Outline the advantages of preparing farm enterprise analysis accounts.",a:"Purposes of a General Profit & Loss Account:\n• Expenses or gains that cannot be allocated directly to the individual farm enterprises are included in this account.\n• It is used to ascertain the overall profit or loss of a farm.\n\nAdvantages of preparing farm enterprise analysis accounts:\n• Allows better planning and decision making and resources can be diverted elsewhere if necessary.\n• Allows costs to be allocated to the relevant individual activity within the farm.\n• The farmer can find the profit/loss on each individual farm activity.\n• The contribution of an individual enterprise towards total profit can be seen."},
  {topic:"Farm Accounts",year:2020,marks:6,tags:["Stock Valuation"],q:"Outline the implications of an incorrect closing stock valuation for McAteer.",a:"Incorrect valuation of stock affects:\n1. The financial statements of two years or two accounting periods — the closing stock of one accounting period and the opening stock of the next.\n2. The figures for cost of sales, gross profit, net profit and the farm's tax liability.\n3. In carrying out ratio analysis the figure for stock will affect the stock turnover, percentage mark-up on cost, gross profit percentage, net profit percentage and the current ratio.\n4. The amount the farm may be able to borrow."},
  // ═══ INCOMPLETE RECORDS (David Wilson 2001–2015) ═══
  {topic:"Incomplete Records",year:2001,marks:10,tags:["Record-Keeping Advice"],q:"Summary of the advice you would give Quaid in relation to record-keeping.",a:"I would advise that Quaid should keep:\n• Day books — including a detailed Cash Book, Sales Book, Purchases Book.\n• Ledgers — including detailed Debtors, Creditors and General Ledger.\n• Keep a Trial Balance.\n\nThis would enable Quaid to prepare an accurate Trading P&L and Balance Sheet and help avoid reliance on estimates."},
  {topic:"Incomplete Records",year:2003,marks:10,tags:["Record-Keeping Advice"],q:"Summary of the advice you would give to O'Higgins in relation to the information given above.",a:"O'Higgins should maintain proper books of first entry (Cash Book, Sales Book, Purchases Book), post these to ledger accounts (Debtors, Creditors and General Ledger), and prepare a regular Trial Balance. Using a full double-entry system removes reliance on estimates and produces accurate Trading, P&L and Balance Sheet figures."},
  {topic:"Incomplete Records",year:2005,marks:8,tags:["Double Entry"],q:"What additional information would be available if Connolly's accounts were prepared using the 'double entry' system?",a:"Additional information available:\n• General ledger accounts.\n• Total sales figure (cash and credit).\n• Bank balance.\n• Expenses due and prepaid.\n• Discounts allowed or received.\n• Trial balance.\n• Total purchases figure (cash and credit).\n• Capital and drawings.\n• Bad debts."},
  {topic:"Incomplete Records",year:2007,marks:8,tags:["Accounting Concepts"],q:"Explain the term Accounting Concept. Name TWO fundamental accounting concepts. Illustrate an accounting concept applying to the accounts of P. Lynch.",a:"Accounting Concepts are rules that are applied/used when preparing financial statements.\n\nFundamental accounting concepts include:\n• The Accruals Concept\n• The Going Concern Concept\n• The Consistency Concept\n• The Prudence Concept\n\nFor example, the Accruals concept matches expenses and gains to a specific period. All expenses incurred and income gained in a particular period must be included in the accounts of that period whether they have been paid/received or not — so for P. Lynch any expense outstanding at year end is added to the relevant expense in the P&L and shown as a current liability in the balance sheet."},
  {topic:"Incomplete Records",year:2009,marks:10,tags:["Record-Keeping Advice"],q:"Summary of the advice you would give to Fuller in relation to the information given above.",a:"Fuller should move from incomplete records to a proper double-entry system: keep books of first entry (Cash Book, Sales Book, Purchases Book), post to Debtors, Creditors and General Ledger accounts, and extract a Trial Balance at regular intervals. This removes reliance on estimates and gives reliable Trading P&L and Balance Sheet figures, supports tax returns and loan applications, and reduces the risk of fraud or error."},
  {topic:"Incomplete Records",year:2011,marks:8,tags:["Record-Keeping Advice"],q:"What advice would you give O'Hagan in relation to record keeping?",a:"I would advise O'Hagan to:\n• Keep proper books of first entry — Cash Book, Sales Book, Purchases Book.\n• Post entries to ledger accounts — Debtors, Creditors and General Ledger.\n• Use accounting software to reduce errors and accounting fees.\n• Prepare a Trial Balance regularly.\n\nThis enables preparation of accurate Trading P&L and Balance Sheet figures and avoids reliance on estimates."},
  {topic:"Incomplete Records",year:2013,marks:8,tags:["Double Entry"],q:"What additional information would be available to Kelly if he used the 'double entry' system to record financial transactions?",a:"• General ledger accounts.\n• Total sales figure (cash and credit).\n• Bank balance.\n• Expenses due and prepaid.\n• Discounts allowed or received.\n• Trial balance.\n• Total purchases figure (cash and credit).\n• Capital and drawings.\n• Bad debts."},
  {topic:"Incomplete Records",year:2015,marks:8,tags:["Accruals Concept"],q:"Explain the 'Accruals Concept' and why it is fundamental to Accounting practice.",a:"The Accruals concept matches expenses and gains to a specific period. All expenses incurred and income gained in a particular period must be included in the accounts of that period whether they have been paid/received or not.\n\nIt is fundamental because financial statements are prepared on this basis rather than on a 'cash' basis. If statements were not prepared using this concept, profits and assets would be over- or understated for the period because expenses and income included/excluded may refer to a past or future period. Accruals ensures the accounts refer only to that specific period."},
  // ═══ PRESERVED (topics outside the David Wilson PDF range) ═══
  {topic:"Published Accounts",year:2005,marks:8,tags:["Companies Act","True and Fair View"],q:"What requirements does the Companies Act place on published accounts?",a:"Must give a true and fair view. Must comply with accounting standards (FRS). Must be audited by an independent auditor. Must include: Directors' Report, Profit and Loss Account, Balance Sheet, Notes to the Accounts. Must be filed with the CRO. Must be presented to shareholders at the AGM."},
  {topic:"Published Accounts",year:2007,marks:8,tags:["Audit","Qualified Report"],q:"What is an audit? Distinguish between a qualified and unqualified report.",a:"Audit: an independent examination of financial statements by a qualified auditor who expresses an opinion.\n\nUnqualified (clean) report: the auditor is satisfied the accounts give a true and fair view.\n\nQualified report: the auditor has reservations — there may be disagreement on accounting policies, limitation of scope, or non-compliance with standards."},
  {topic:"Published Accounts",year:2009,marks:10,tags:["Notes to Accounts","True and Fair View"],q:"What information is contained in the notes to published accounts?",a:"Notes include: Accounting policies used (depreciation method, stock valuation). Fixed assets schedule (cost, accumulated depreciation, NBV, additions, disposals). Breakdown of debtors and creditors. Details of share capital (authorised, issued). Reserves movements. Contingent liabilities. Exceptional items detail. Related party transactions. Directors' emoluments. Employees and wages information."},
  {topic:"Published Accounts",year:2011,marks:10,tags:["Audit","Directors Report"],q:"What is an audit? Distinguish between a qualified and unqualified auditor's report. List contents of a Directors' Report.",a:"Audit: an independent examination of the financial statements of a company by an appointed auditor. The auditor expresses an opinion on whether the accounts give a true and fair view.\n\nUnqualified Report (clean): the auditor IS satisfied that the accounts give a true and fair view, comply with the Companies Acts, and all information and explanations were made available.\n\nQualified Report: the auditor is NOT satisfied — there may be disagreement on accounting policies, limitation on the scope of the audit, or non-compliance with accounting standards.\n\nDirectors' Report must include: dividends recommended, amounts transferred to reserves, changes in the nature of the business, a fair review of the year, principal activities, important post-balance sheet events, likely future developments, R&D activities, changes in fixed assets, directors' share dealings."},
  {topic:"Published Accounts",year:2013,marks:8,tags:["Exceptional Items","Contingent Liabilities"],q:"Explain the treatment of exceptional items and contingent liabilities in published accounts.",a:"Exceptional Items: material items of significant size that arise from ordinary activities but are unusual in size or incidence. Must be shown separately in the P&L to highlight their effect. E.g. profit/loss on sale of a fixed asset, abnormally large bad debt, restructuring costs.\n\nContingent Liabilities: potential obligations that depend on a future event. If PROBABLE: provide for the estimated amount in the accounts and include an explanatory note. If POSSIBLE but unlikely: no provision needed, but include a note showing the nature, estimated amount, and opinion of the outcome. If REMOTE: no provision or note required."},
  {topic:"Published Accounts",year:2016,marks:10,tags:["Companies Act","Directors Report"],q:"List the contents of a Directors' Report. What are the main requirements of the Companies Act for published accounts?",a:"Directors' Report: dividends recommended, amounts to reserves, review of the year, principal activities, post-balance sheet events, future developments, R&D, changes in fixed assets, directors' interests in shares.\n\nCompanies Act requirements: accounts must give a true and fair view, be audited, include P&L, balance sheet, notes, directors' report, and cash flow statement. Filed with CRO and presented at AGM."},
  {topic:"Published Accounts",year:2020,marks:8,tags:["Exceptional Items","Notes to Accounts"],q:"Explain exceptional items. Why are notes to the accounts important?",a:"Exceptional Items: material items arising from ordinary activities that are unusual in size or incidence. Shown separately in the P&L.\n\nNotes are important because: they provide additional detail not shown in the main statements. Required by law and accounting standards. Include accounting policies, fixed asset schedules, breakdown of debtors/creditors, share capital details, contingent liabilities, and other disclosures that help users understand the accounts."},
  {topic:"Published Accounts",year:2024,marks:8,tags:["Audit","True and Fair View"],q:"What is the role of the auditor? What does 'true and fair view' mean?",a:"Auditor: independent person who examines the financial statements and expresses an opinion on whether they give a true and fair view. Reports to shareholders. Must be qualified and independent.\n\nTrue and Fair View: the accounts represent the financial position honestly and accurately. Free from material misstatement. Prepared in accordance with accounting standards and the Companies Act."},
  {topic:"Service Firms",year:2004,marks:6,tags:["Statement of Capital"],q:"What is a statement of capital for a service firm?",a:"A Statement of Capital is the opening balance sheet showing the firm's financial position at the start of the period. It lists all assets less all liabilities to arrive at the opening capital. This is equivalent to the accumulated fund in a club. Service firms include dentists, solicitors, veterinarians, and accountants."},
  {topic:"Service Firms",year:2007,marks:8,tags:["Statement of Capital","Fee Income"],q:"Explain a Statement of Capital for a service firm. How is fee income treated?",a:"Statement of Capital: the opening balance sheet of a service firm (e.g. dentist, solicitor, veterinarian). Lists all assets at the start of the period minus all liabilities = Opening Capital. This is equivalent to the Accumulated Fund in a club.\n\nFee Income: the main source of revenue for a service firm. Fees earned during the period are recorded as income in the Income & Expenditure Account. Adjust for fees due but not yet received (debtors) and fees received in advance (creditor/deferred income). There is no Trading Account because a service firm has no stock for resale."},
  {topic:"Service Firms",year:2010,marks:6,tags:["Fee Income","Expenses"],q:"How does a service firm differ from a trading business?",a:"A service firm provides services rather than selling goods. No stock for resale, so no trading account. Main income is fee income (not sales). The I&E account replaces the P&L. No cost of sales or gross profit. Statement of capital replaces opening balance sheet."},
  {topic:"Service Firms",year:2014,marks:8,tags:["Statement of Capital","Adjustments"],q:"What adjustments are typically made in service firm accounts?",a:"Depreciation of fixed assets. Accrued expenses (bills due but not yet paid). Prepaid expenses (bills paid in advance). Fees due but not received (debtors). Fees received in advance (deferred income/creditor). Bad debts write-off. Provision for bad debts. Private use of business assets (drawings)."},
  {topic:"Service Firms",year:2018,marks:6,tags:["Fee Income"],q:"Explain the treatment of fee income in a service firm. Why is there no trading account?",a:"Fee income: the main revenue source. Calculated on an accruals basis: fees received + closing fees due − opening fees due − closing fees in advance + opening fees in advance.\n\nNo trading account because a service firm does not buy and sell goods — it provides professional services. There is no stock, no purchases, and no cost of sales."},
  {topic:"Service Firms",year:2022,marks:8,tags:["Statement of Capital","Fee Income"],q:"Explain statement of capital and fee income for a service firm.",a:"Statement of Capital: the opening balance sheet — total assets less total liabilities = opening capital. Equivalent of accumulated fund.\n\nFee Income: the primary revenue source, calculated on an accruals basis. Adjust for fees due and fees received in advance. No trading account since no goods are traded."},
  {topic:"Interpretation",year:2005,marks:10,tags:["Ratio Analysis","Stakeholders"],q:"Why is ratio analysis useful? Name users of financial statements.",a:"Ratio analysis allows: meaningful comparison between years (trend analysis). Comparison between similar companies. Puts figures in context — a single figure alone is meaningless. Highlights strengths and weaknesses. Helps stakeholders make decisions.\n\nUsers: Shareholders, Bank Manager, Creditors, Employees, Revenue Commissioners, Management, Financial Commentators, Competitors, Potential Investors."},
  {topic:"Interpretation",year:2008,marks:8,tags:["Liquidity","Profitability"],q:"How might a company improve its liquidity position? How might it improve profitability?",a:"Improve Liquidity: issue shares for cash, sell investments, reduce stock levels, collect debts faster, delay paying creditors, reduce drawings/dividends, sale and leaseback of assets.\n\nImprove Profitability: increase selling price, reduce cost of materials (cheaper supplier), cut overheads, advertise to increase volume, improve stock turnover."},
  {topic:"Interpretation",year:2010,marks:10,tags:["Gearing","Interest Cover"],q:"Explain gearing. What is interest cover? What level would a bank prefer?",a:"Gearing: the proportion of a company's long-term finance that comes from debt (borrowings) versus equity (shareholders' funds). Gearing Ratio = Long-term Liabilities / Capital Employed × 100. Below 50% = low geared (safer). Above 50% = high geared (risky).\n\nInterest Cover: the number of times operating profit covers interest payments. Interest Cover = Operating Profit / Interest Payable. A bank would prefer interest cover of at least 3-4 times — shows the company can comfortably afford its interest payments."},
  {topic:"Interpretation",year:2012,marks:8,tags:["Limitations","Stock Turnover"],q:"What are the limitations of ratio analysis? Why is stock turnover important?",a:"Limitations: Based on historical data. Don't account for non-financial factors (staff morale, location, brand). Subject to seasonal fluctuations. Balance sheet is one point in time. Different accounting policies affect comparisons. Window dressing can distort figures.\n\nStock Turnover: shows how many times stock is sold and replaced during the year. Higher = better (faster-selling, less risk of obsolescence, lower holding costs). Each turnover generates profit through markup."},
  {topic:"Interpretation",year:2014,marks:10,tags:["Ratio Analysis","Stakeholders"],q:"Why is ratio analysis useful? Name three stakeholders who use financial statements.",a:"Ratio analysis is useful because: it allows meaningful comparison of performance between years (trend analysis). It allows comparison between similar companies. A single figure in isolation means little — ratios put figures in context. Highlights areas of strength and weakness. Helps stakeholders make informed decisions.\n\nStakeholders: Shareholders/Investors — to assess profitability and return on investment. Bank Manager/Creditors — to assess the company's ability to repay loans (liquidity and solvency). Debenture Holders — to assess the security of their investment and the company's ability to pay interest."},
  {topic:"Interpretation",year:2017,marks:10,tags:["Liquidity","Gearing"],q:"How might a company improve its liquidity? What is gearing and why does it matter?",a:"Improve Liquidity: issue shares, sell investments, chase debtors, reduce stock, delay creditor payments, sale and leaseback, cut dividends.\n\nGearing: the proportion of long-term finance from debt vs equity. High gearing = more debt = higher risk (must pay interest regardless of profits). Low gearing = more equity = lower risk. Banks prefer low gearing when lending."},
  {topic:"Interpretation",year:2020,marks:8,tags:["Stakeholders","Limitations"],q:"Name users of published accounts. State limitations of ratio analysis.",a:"Users: Shareholders, bank, creditors, employees, Revenue Commissioners, management, competitors, financial commentators, potential investors.\n\nLimitations: historical data, seasonal fluctuations, one point in time, different accounting policies, non-financial factors ignored, window dressing."},
  {topic:"Interpretation",year:2024,marks:10,tags:["Ratio Analysis","Profitability"],q:"Why is ratio analysis useful? How can a company improve profitability?",a:"Useful because: allows comparison between years and companies. Puts figures in context. Identifies trends. Highlights strengths and weaknesses.\n\nImprove profitability: increase prices, find cheaper suppliers, cut overheads, advertise to boost sales, improve stock turnover, reduce bad debts."},
  {topic:"Tabular Statements",year:2006,marks:8,tags:["Double Entry","Tabular Format"],q:"What is a tabular statement? How does it differ from traditional double-entry ledger accounts?",a:"Tabular Statement: presents the double-entry system in columnar (spreadsheet) format. Each column represents a different account. Each transaction is entered on one row showing the debit and credit effects simultaneously. Balances are running totals at the bottom.\n\nDiffers from traditional ledger: ledger accounts have separate T-accounts for each item. Tabular format shows all accounts side by side. Easier to see the overall effect of each transaction. The trial balance can be read directly from the final row."},
  {topic:"Tabular Statements",year:2012,marks:6,tags:["Tabular Format"],q:"Explain the advantages of using a tabular statement.",a:"All accounts visible on one page. Running balances updated after each transaction. Easy to see the double-entry effect of each transaction. Trial balance can be read directly from the bottom row. Good for teaching double-entry principles. Reduces errors as both sides of each entry are recorded on the same line."},
  {topic:"Tabular Statements",year:2019,marks:8,tags:["Double Entry","Tabular Format"],q:"Explain how a tabular statement works. What appears in the final row?",a:"Each column represents a different account (Cash, Bank, Debtors, Creditors, Capital, etc.). Each row represents a transaction — the debit entry appears in one column and the credit entry in another. After each transaction, running balances are calculated. The final row shows the closing balance of each account — this is effectively the trial balance. Total debits must equal total credits."},
  {topic:"Manufacturing",year:2007,marks:8,tags:["Manufacturing Account","Prime Cost"],q:"Explain the structure of a manufacturing account. Define prime cost.",a:"Manufacturing Account shows the total cost of producing goods:\n1. Direct Materials (Opening RM + Purchases − Closing RM)\n2. Direct Labour\n3. Direct Expenses\n= Prime Cost\n4. Add Factory Overheads (indirect costs)\n= Factory Cost of Production\n5. Adjust for Work in Progress (Opening WIP − Closing WIP)\n= Cost of Finished Goods\n\nPrime Cost: the total of all DIRECT costs — direct materials, direct labour, and direct expenses. These costs can be directly traced to the product."},
  {topic:"Manufacturing",year:2011,marks:8,tags:["Factory Overheads","WIP"],q:"What are factory overheads? How is work in progress treated?",a:"Factory Overheads: indirect production costs that cannot be traced directly to individual products. E.g. factory rent, factory insurance, factory power, depreciation of factory machinery, factory maintenance, indirect factory wages, factory rates.\n\nWork in Progress (WIP): goods that are partially completed at the end of the period. Closing WIP is deducted from factory cost of production (it will be completed next period). Opening WIP is added (these goods were completed this period). Closing WIP appears as a current asset on the balance sheet."},
  {topic:"Manufacturing",year:2016,marks:6,tags:["Manufacturing Account"],q:"Distinguish between direct and indirect costs in manufacturing.",a:"Direct Costs: costs that can be directly traced to the product being manufactured. Include: direct materials (raw materials used), direct labour (factory workers' wages), direct expenses (e.g. royalties per unit). Total = Prime Cost.\n\nIndirect Costs (Factory Overheads): cannot be traced directly to a specific product. Include: factory rent, factory insurance, depreciation of factory equipment, factory heat and power, indirect wages (supervisor, security). These are added after prime cost."},
  {topic:"Manufacturing",year:2023,marks:8,tags:["Prime Cost","Factory Overheads"],q:"Define prime cost and factory overheads. How is cost of production calculated?",a:"Prime Cost: total direct costs — direct materials + direct labour + direct expenses.\n\nFactory Overheads: indirect production costs — factory rent, insurance, power, depreciation of factory assets, indirect wages.\n\nCost of Production: Prime Cost + Factory Overheads ± adjustment for WIP (+ Opening WIP − Closing WIP) = Cost of Finished Goods transferred to Trading Account."},
  {topic:"Company Appropriation",year:2009,marks:8,tags:["Dividends","Reserves"],q:"What is an appropriation account? Distinguish between interim and final dividends.",a:"Appropriation Account: shows how the profit after tax is distributed. Items include: dividends (interim and final), transfers to reserves, retained profit carried forward.\n\nInterim Dividend: paid during the year based on expected profits. Recorded as a payment (cash outflow).\n\nFinal Dividend: declared by directors at year end and proposed at the AGM. Appears as a current liability (creditors < 1 year) on the balance sheet if not yet paid."},
  {topic:"Company Appropriation",year:2015,marks:6,tags:["Reserves","Retained Profits"],q:"Distinguish between capital reserves and revenue reserves.",a:"Capital Reserves: arise from capital transactions, NOT from trading profits. Cannot be used to pay dividends. E.g. Share Premium (excess over nominal value when shares issued), Revaluation Reserve (increase in value of fixed asset).\n\nRevenue Reserves: arise from trading profits. CAN be used to pay dividends. E.g. General Reserve (set aside for future use), Retained Profits/P&L balance (accumulated undistributed profits)."},
  {topic:"Company Appropriation",year:2020,marks:6,tags:["Dividends","Corporation Tax"],q:"Explain the treatment of corporation tax and dividends in company accounts.",a:"Corporation Tax: calculated on the company's taxable profit. Shown as an expense in the P&L (Profit before tax − Corporation tax = Profit after tax). The unpaid amount at year end is a current liability (creditors < 1 year).\n\nDividends: an appropriation of profit, NOT an expense. Shown in the Appropriation Account after profit after tax. Proposed dividends appear as a current liability on the balance sheet."},
];

export const THEORY_FLASHCARDS: Flashcard[] = [
  // Budgeting (11)
  {term:"Adverse Variance",def:"When actual costs exceed budgeted costs.",topic:"Budgeting"},
  {term:"Favourable Variance",def:"When actual costs are less than budgeted costs.",topic:"Budgeting"},
  {term:"Principal Budget Factor",def:"The limiting factor that limits output and prevents continuous expansion. Usually sales demand.",topic:"Budgeting"},
  {term:"Cash Budget",def:"A forecast or plan of cash inflow and cash outflow over a period.",topic:"Budgeting"},
  {term:"Capital Budget",def:"Deals with planned capital expenditure (e.g. purchase of fixed assets) and planned capital receipts (e.g. sale of fixed assets).",topic:"Budgeting"},
  {term:"Master Budget",def:"A summary of all the other budgets providing an overview of operations for the planned period.",topic:"Budgeting"},
  {term:"Flexible Budget",def:"A budget prepared to compare budgeted costs and actual costs at the same level of activity.",topic:"Budgeting"},
  {term:"Sensitivity Analysis",def:"Also known as 'what if' analysis. A technique to show the effect on profit of changes in selling price, sales volume, variable costs, or fixed costs.",topic:"Budgeting"},
  {term:"Controllable Costs",def:"Costs that can be controlled by the manager of a cost centre. E.g. all variable costs.",topic:"Budgeting"},
  {term:"Uncontrollable Costs",def:"Costs over which the manager of a cost centre has no control. E.g. rates to the local authority.",topic:"Budgeting"},
  {term:"Budgetary Control",def:"The process of comparing budgeted figures with actual figures, identifying variances, and taking corrective action.",topic:"Budgeting"},

  // Costing (10)
  {term:"Contribution",def:"Sales revenue less variable costs. Goes towards paying off fixed costs, then profit.",topic:"Costing"},
  {term:"Break-Even Point",def:"The level of output where total revenue equals total costs (zero profit/loss).",topic:"Costing"},
  {term:"Marginal Costing",def:"A costing method that does NOT include fixed costs in the cost of a product. Only variable costs are charged.",topic:"Costing"},
  {term:"Absorption Costing",def:"A costing method that includes ALL costs (fixed and variable) in the cost of a product. Required for financial accounting.",topic:"Costing"},
  {term:"Over-absorption",def:"When overheads charged to production are greater than actual overheads incurred. Costs are over-recovered.",topic:"Costing"},
  {term:"Under-absorption",def:"When overheads charged to production are less than actual overheads incurred. Costs are under-recovered.",topic:"Costing"},
  {term:"Re-apportionment",def:"Service department costs are re-allocated to production departments because overheads can only be recovered through production.",topic:"Costing"},
  {term:"Step Fixed Cost",def:"A cost that is fixed within a certain range of activity but changes (steps up) outside that range. E.g. rent increasing when a larger factory is needed.",topic:"Costing"},
  {term:"Overhead Absorption Rate",def:"A rate used to charge overheads to products. Calculated per labour hour, per machine hour, per unit, or as a % of prime cost.",topic:"Costing"},
  {term:"Margin of Safety",def:"The amount by which actual or expected sales exceed the break-even point. Shows how much sales can fall before losses occur.",topic:"Costing"},

  // Cash Flow (6)
  {term:"Non-Cash Item",def:"An item in the P&L that affects profit but not cash. E.g. depreciation, increase in bad debt provision, goodwill written off.",topic:"Cash Flow"},
  {term:"Cash Flow Statement",def:"A financial statement showing cash inflows and outflows classified into operating, investing, and financing activities.",topic:"Cash Flow"},
  {term:"Operating Activities",def:"Cash flows from the main revenue-generating activities. Operating profit adjusted for non-cash items and working capital changes.",topic:"Cash Flow"},
  {term:"Reconciliation (Cash Flow)",def:"Links the net cash flow to the movement in cash on the balance sheet. Opening cash ± net cash flow = closing cash.",topic:"Cash Flow"},
  {term:"Capital Expenditure",def:"Cash spent on buying fixed assets or received from selling them. Shown separately in the cash flow statement.",topic:"Cash Flow"},
  {term:"Cash vs Profit",def:"A company can be profitable but have cash problems due to credit sales, stock build-up, capital expenditure, or loan repayments.",topic:"Cash Flow"},

  // Correction of Errors (6)
  {term:"Suspense Account",def:"A temporary account used to make the trial balance agree when errors cause an imbalance, until the errors are found and corrected.",topic:"Correction of Errors"},
  {term:"Error of Commission",def:"The correct amount is posted to the correct side of the WRONG account (but same type of account). Not revealed by trial balance.",topic:"Correction of Errors"},
  {term:"Error of Principle",def:"An item is posted to the wrong CLASS of account. E.g. a vehicle treated as a purchase of stock. Not revealed by trial balance.",topic:"Correction of Errors"},
  {term:"Error of Original Entry",def:"The wrong amount is entered in the book of original entry and posted to both sides. Not revealed by trial balance.",topic:"Correction of Errors"},
  {term:"Compensating Errors",def:"Two errors of equal but opposite amounts that cancel each other out. The trial balance still agrees.",topic:"Correction of Errors"},
  {term:"Complete Reversal",def:"An entry where both debit and credit are on the wrong side. The correct amount is used but sides are swapped.",topic:"Correction of Errors"},

  // Club Accounts (7)
  {term:"Accumulated Fund",def:"The club equivalent of capital. Excess of assets over liabilities. Calculated in the opening statement of affairs.",topic:"Club Accounts"},
  {term:"Levy (Club)",def:"A payment made by club members to fund a special project. Credited to a reserve fund. Treated as a long-term liability until used.",topic:"Club Accounts"},
  {term:"Life Membership",def:"A one-off fee entitling a member to use the club for life. Treated as a long-term liability and written off to income over a stated number of years.",topic:"Club Accounts"},
  {term:"Income & Expenditure A/c",def:"The club equivalent to a P&L account. Prepared on an accruals basis.",topic:"Club Accounts"},
  {term:"Receipts & Payments A/c",def:"A summary of the cash book showing all cash received and paid. Cash-based, not accruals-based. Limitations: ignores depreciation and amounts owed.",topic:"Club Accounts"},
  {term:"Special Purpose P&L",def:"A separate account for a specific fundraising event (e.g. dance, raffle). Profit/loss transferred to I&E Account.",topic:"Club Accounts"},
  {term:"Subscriptions (Club)",def:"Members' annual fees. Calculated on accruals basis for I&E account. Adjust for amounts due and in advance.",topic:"Club Accounts"},

  // Published Accounts (6)
  {term:"Audit",def:"An independent examination of the financial statements by an appointed auditor, who expresses an opinion on truth and fairness.",topic:"Published Accounts"},
  {term:"Exceptional Item",def:"A material item of significant size arising from ordinary activities. Must be shown separately in the P&L.",topic:"Published Accounts"},
  {term:"Contingent Liability",def:"A potential obligation depending on a future event. If probable: provide for it. If possible: note it. If remote: ignore.",topic:"Published Accounts"},
  {term:"True and Fair View",def:"Accounts represent the financial position honestly, free from material misstatement, prepared per accounting standards.",topic:"Published Accounts"},
  {term:"Directors' Report",def:"Accompanies published accounts. Includes: dividends, review of year, principal activities, future developments, R&D, fixed asset changes.",topic:"Published Accounts"},
  {term:"Notes to Accounts",def:"Additional disclosures: accounting policies, fixed asset schedule, debtors/creditors breakdown, share capital, contingent liabilities.",topic:"Published Accounts"},

  // Incomplete Records (4)
  {term:"Incomplete Records",def:"When a business does not keep complete double-entry books. Information must be reconstructed from available records.",topic:"Incomplete Records"},
  {term:"Statement of Affairs",def:"A balance sheet prepared from incomplete records to calculate opening or closing capital. Profit = Closing Capital − Opening Capital + Drawings − Capital Introduced.",topic:"Incomplete Records"},
  {term:"Mark-Up",def:"Profit expressed as a percentage of COST. E.g. 25% mark-up on cost of €100 = selling price €125.",topic:"Incomplete Records"},
  {term:"Margin",def:"Profit expressed as a percentage of SELLING PRICE. E.g. 20% margin on sales of €125 = profit €25.",topic:"Incomplete Records"},

  // Depreciation (5)
  {term:"Straight Line Depreciation",def:"The same amount of cost is written off each year over the useful life. Appropriate for assets that lose value slowly (e.g. buildings).",topic:"Depreciation"},
  {term:"Reducing Balance Depreciation",def:"A constant percentage is applied to the reducing carrying amount each year. Higher depreciation in early years. Appropriate for vehicles, computers.",topic:"Depreciation"},
  {term:"Causes of Depreciation",def:"Wear and tear (physical use), obsolescence (technological change), passage of time (leases, patents).",topic:"Depreciation"},
  {term:"Disposal Account",def:"Records the sale of a fixed asset. Cost transferred in, accumulated depreciation transferred out, proceeds recorded. Balance = profit/loss on disposal.",topic:"Depreciation"},
  {term:"Revaluation Reserve",def:"A capital reserve arising when a fixed asset is revalued upward. Cannot be used to pay dividends.",topic:"Depreciation"},

  // Service Firms (3)
  {term:"Statement of Capital",def:"The opening balance sheet of a service firm. Assets minus liabilities = opening capital. Equivalent of accumulated fund.",topic:"Service Firms"},
  {term:"Fee Income",def:"The main revenue source for a service firm. Calculated on accruals basis — adjust for fees due and fees received in advance.",topic:"Service Firms"},
  {term:"Service Firm",def:"A business providing professional services (e.g. dentist, solicitor). No trading account, no stock. Main income is fees.",topic:"Service Firms"},

  // Interpretation (4)
  {term:"Ratio Analysis",def:"Using financial ratios to compare performance between years and companies. Includes profitability, liquidity, efficiency, and gearing ratios.",topic:"Interpretation"},
  {term:"Gearing",def:"The proportion of long-term finance from debt vs equity. High gearing = more debt = higher risk.",topic:"Interpretation"},
  {term:"Interest Cover",def:"Operating Profit / Interest Payable. Shows how many times the company can cover its interest payments. Higher = safer.",topic:"Interpretation"},
  {term:"Window Dressing",def:"Manipulating accounts to present a more favourable picture. E.g. delaying payments to inflate cash, timing asset sales.",topic:"Interpretation"},

  // Manufacturing (3)
  {term:"Prime Cost",def:"Total direct costs: direct materials + direct labour + direct expenses. Costs directly traceable to the product.",topic:"Manufacturing"},
  {term:"Factory Overheads",def:"Indirect production costs: factory rent, insurance, power, depreciation. Cannot be traced directly to a specific product.",topic:"Manufacturing"},
  {term:"Work in Progress",def:"Partially completed goods at period end. Closing WIP is a current asset. Adjusts the cost of production in the manufacturing account.",topic:"Manufacturing"},

  // Tabular Statements (2)
  {term:"Tabular Statement",def:"Double-entry system in columnar format. Each column is an account, each row is a transaction. Final row gives the trial balance.",topic:"Tabular Statements"},
  {term:"Running Balance",def:"A balance updated after each transaction in a tabular statement. Shows the current position of each account at any point.",topic:"Tabular Statements"},

  // Company Appropriation (3)
  {term:"Appropriation Account",def:"Shows how profit after tax is distributed: dividends, transfers to reserves, retained profits.",topic:"Company Appropriation"},
  {term:"Capital Reserve",def:"Arises from capital transactions (e.g. share premium, revaluation). Cannot be used to pay dividends.",topic:"Company Appropriation"},
  {term:"Revenue Reserve",def:"Arises from trading profits (e.g. general reserve, retained profits). CAN be used to pay dividends.",topic:"Company Appropriation"},

  // Farm Accounts (2)
  {term:"Herd Basis",def:"Breeding herd treated as a fixed asset, not depreciated. Maintains value through replacement. Young stock = current asset.",topic:"Farm Accounts"},
  {term:"Enterprise Analysis",def:"Shows profitability of each farming activity separately (dairy, tillage, beef). Helps decide which to expand or contract.",topic:"Farm Accounts"},
];

// Supplementary flashcards from study notes
export const THEORY_FLASHCARDS_SUPPLEMENT: Flashcard[] = [
  {term:"Entity Concept",def:"The business exists in its own right — separate from its owners. A clear distinction is made between the owner's business and their private affairs.",topic:"Incomplete Records"},
  {term:"Net Worth",def:"Total Assets − Total Outside Liabilities. The change in Net Worth shows profit or loss (adjusted for drawings and capital introduced).",topic:"Incomplete Records"},
  {term:"Consistency Concept",def:"A business uses the same accounting methods from one year to the next, allowing meaningful comparisons of performance over time. If a method is changed, it must be clearly disclosed.",topic:"Incomplete Records"},
  {term:"Going Concern Concept",def:"Financial statements are prepared on the assumption that the business will continue to operate in the foreseeable future.",topic:"Incomplete Records"},
  {term:"Prudence Concept",def:"Caution should be exercised when preparing financial statements. Only realised profits are included; provision is made for all expected expenses and losses.",topic:"Incomplete Records"},
  {term:"Goodwill",def:"An intangible asset. Arises when a business is bought for more than its net asset value due to reputation, customer base, staff etc.",topic:"Incomplete Records"},
  {term:"Useful Economic Life",def:"The expected period during which a fixed asset remains beneficial to the business — i.e. how long the asset is expected to contribute to generating income before becoming obsolete or uneconomic to use.",topic:"Depreciation"},
  {term:"Residual Value",def:"The estimated amount that an asset will be worth at the end of its useful life. Subtracted from the asset's original cost to determine annual depreciation.",topic:"Depreciation"},
  {term:"Revaluation Reserve (Capital)",def:"Arises when land and buildings have increased in value. The profit on revalued assets cannot be distributed because the assets have not actually been sold — it sits as a capital reserve until disposal.",topic:"Depreciation"},
  {term:"Capital Expenditure",def:"Expenditure on items where the benefit derived is expected to last for more than one year (e.g. purchase of fixed assets).",topic:"Depreciation"},
  {term:"Revenue Expenditure",def:"Expenditure on items where the benefit derived is of a temporary nature (less than one year, e.g. rates, light & heat).",topic:"Depreciation"},
  {term:"Liquidity",def:"The ability of a company to pay its short-term debts as they fall due. Measured by the acid test ratio: ideally €1 of liquid assets for every €1 owed short term.",topic:"Interpretation"},
  {term:"Solvency",def:"The ability of a company to pay all debts, short and long term, as they fall due. A company is solvent if total assets exceed total outside liabilities.",topic:"Interpretation"},
  {term:"Gearing (def)",def:"Measure of how a business is financed long-term. Fixed-interest debt (debentures + preference shares) as a proportion of capital employed. <50% = low geared; >50% = high geared. Low is preferred.",topic:"Interpretation"},
  {term:"Ordinary Shareholders",def:"Have voting rights (1 share = 1 vote). Not guaranteed a dividend — receive one only if the company has sufficient profit and directors recommend it.",topic:"Published Accounts"},
  {term:"Preference Shareholders",def:"No voting rights. Have priority over ordinary shareholders for dividends and receive a set percentage each year.",topic:"Published Accounts"},
  {term:"Directors' Report (contents)",def:"Principal activities and any changes; likely future developments; significant changes in fixed assets; amounts transferred to reserves; important events affecting the company; dividends paid or planned.",topic:"Published Accounts"},
  {term:"Audit",def:"An independent examination and the expression of opinion on the financial statements of a company by an appointed auditor. Auditors are appointed by and report to the shareholders at the AGM.",topic:"Published Accounts"},
  {term:"Qualified Audit Report",def:"The auditor is NOT satisfied with one or more of: true and fair view; compliance with Companies Acts; all information available; consistency between directors' report and statements.",topic:"Published Accounts"},
  {term:"Unqualified (Clean) Report",def:"The auditor IS satisfied that the financial statements give a true and fair view, comply with the Companies Acts, all information was available, and directors' information is consistent.",topic:"Published Accounts"},
  {term:"Exceptional Item",def:"A profit or loss of significant size that must be shown separately in the P&L account, e.g. profit/loss on sale of land.",topic:"Published Accounts"},
  {term:"Contingent Liability (Probable)",def:"If a future liability is probable, the expected loss must be included in the P&L (administration expense) and the balance sheet as an amount due, with an explanatory note.",topic:"Published Accounts"},
  {term:"Contingent Liability (Possible)",def:"If a future liability is possible but unlikely, no provision is needed — but a note should describe the nature, estimate the amount, and state the expected outcome.",topic:"Published Accounts"},
  {term:"Debtors Control Account",def:"An independent check on the accuracy of the sales ledger. Detects errors and possible fraud, shows total owed by customers, saves time by posting day-book totals, strengthens internal control.",topic:"Correction of Errors"},
  {term:"Creditors Control Account",def:"Checks the accuracy of the purchases ledger. Detects errors and fraud, shows total owed to suppliers, strengthens internal control, and assists in preparing financial statements.",topic:"Correction of Errors"},
  {term:"Contra Item",def:"Arises when the same person is both a debtor and a creditor. Balances are offset against each other instead of being paid separately; the contra amount is recorded in both control accounts.",topic:"Correction of Errors"},
];
